/* ─── v7 HeroReadout live-tick wrapper ─────────────────────────────────
   V7HeroReadout is a pure display — it accepts elapsedSec/tnkMinLeft/
   evtMinLeft as props and does NOT tick on its own. This wrapper supplies
   the second-by-second tick from an lkwIso input so the readout can be
   dropped into any LKW context with a single prop, mirroring the existing
   <LKWCountdown lkwIso=… /> ergonomics. Windows: IV TNK 0–4.5h (270 min),
   EVT 4.5–24h (1440 min). Pure display — no clinical-state writes. */
const V7HeroReadoutTicker = ({ lkwIso, unknownLkw = false, size = '3xl', className }) => {
  const [now, setNow] = useState(() => Date.now());
  useEffect(() => {
    if (!lkwIso || unknownLkw) return undefined;
    const t = setInterval(() => setNow(Date.now()), 1000);
    return () => clearInterval(t);
  }, [lkwIso, unknownLkw]);
  if (!lkwIso && !unknownLkw) return null;
  const lkwMs = lkwIso ? new Date(lkwIso).getTime() : NaN;
  const elapsedSec = Number.isFinite(lkwMs) ? Math.max(0, Math.floor((now - lkwMs) / 1000)) : 0;
  const elapsedMin = Math.floor(elapsedSec / 60);
  const tnkMinLeft = Math.max(0, 270 - elapsedMin);
  const evtMinLeft = Math.max(0, 1440 - elapsedMin);
  return (
    <V7HeroReadout
      elapsedSec={elapsedSec}
      tnkMinLeft={tnkMinLeft}
      evtMinLeft={evtMinLeft}
      unknownLkw={unknownLkw}
      size={size}
      className={className}
    />
  );
};

        const STORAGE_PREFIX = (window.strokeAppStorage && window.strokeAppStorage.prefix) || 'strokeApp:';
