          const getDefaultSettings = () => ({
            deidMode: true,
            allowFreeTextStorage: false,
            ttlHoursOverride: null,
            defaultConsultationType: 'telephone',
            workflowPersona: 'senior',
            contacts: DEFAULT_CONTACTS,
          });

        const getDefaultAppData = () => ({
          schemaVersion: APP_DATA_SCHEMA_VERSION,
          settings: getDefaultSettings(),
          shiftBoards: [],
          uiState: {
            lastActiveTab: 'encounter',
            lastShiftBoardId: null,
            lastManagementSubTab: 'ich',
            lastLibrarySection: 'management',
            legacyMigratedAt: null,
            searchHighlightId: null,
          },
          encounter: {
            clipboardPacks: getDefaultClipboardPacks(),
            clipboardPackVisibility: {}
          }
        });

        const mergeAppData = (base, incoming) => {
          const merged = {
            ...base,
            ...incoming,
            settings: { ...base.settings, ...(incoming && incoming.settings ? incoming.settings : {}) },
            uiState: { ...base.uiState, ...(incoming && incoming.uiState ? incoming.uiState : {}) },
            encounter: { ...base.encounter, ...(incoming && incoming.encounter ? incoming.encounter : {}) }
          };
          delete merged.pinnedReferences;
          merged.shiftBoards = ensureArray(merged.shiftBoards, []);
          merged.encounter.clipboardPacks = ensureArray(merged.encounter.clipboardPacks, getDefaultClipboardPacks());
          return merged;
        };

        const migrateAppData = (data) => {
          const next = { ...data };
          const version = Number.isFinite(next.schemaVersion) ? next.schemaVersion : 0;
          if (version < APP_DATA_SCHEMA_VERSION) {
            next.schemaVersion = APP_DATA_SCHEMA_VERSION;
          }
          return next;
        };

        const migrateLegacyToAppData = (data) => {
          if (data.uiState && data.uiState.legacyMigratedAt) return data;
          const next = mergeAppData(getDefaultAppData(), data);

          const legacyActiveTab = getKey('activeTab', null);
          if (legacyActiveTab) {
            next.uiState.lastActiveTab = legacyActiveTab;
          }

          const legacyTtl = getKey('ttlHoursOverride', null);
          if (Number.isFinite(Number(legacyTtl)) && Number(legacyTtl) > 0) {
            next.settings.ttlHoursOverride = Number(legacyTtl);
          }


          next.uiState.legacyMigratedAt = toIsoString();
          return next;
        };

        const loadAppData = () => {
          const base = getDefaultAppData();
          const raw = localStorage.getItem(APP_DATA_KEY);
          if (!raw) {
            return migrateLegacyToAppData(base);
          }
          try {
            const parsed = JSON.parse(raw);
            const merged = mergeAppData(base, parsed);
            return migrateLegacyToAppData(migrateAppData(merged));
          } catch (e) {
            console.warn('Failed to parse app data:', e);
            return migrateLegacyToAppData(base);
          }
        };

        const saveAppData = (data) => {
          if (PUBLIC_DEMO_MODE) return;
          try {
            localStorage.setItem(APP_DATA_KEY, JSON.stringify(data));
            touchLastUpdated();
          } catch (e) {
            if (e.name === 'QuotaExceededError' || e.code === 22) {
              console.error('Storage quota exceeded:', e);
              try { document.dispatchEvent(new CustomEvent('storage-quota-exceeded')); } catch (_) {}
            } else {
              console.warn('Failed to save app data:', e);
            }
          }
        };

        const parseLastUpdated = (value) => {
          if (typeof value === 'number' && Number.isFinite(value)) return value;
          if (typeof value === 'string') {
            const numeric = Number(value);
            if (Number.isFinite(numeric)) return numeric;
            const parsedDate = Date.parse(value);
            if (!Number.isNaN(parsedDate)) return parsedDate;
          }
          return null;
        };

        const applyStorageExpiration = (ttlHours) => {
          const lastUpdatedRaw = getKey(LAST_UPDATED_KEY, null);
          const lastUpdated = parseLastUpdated(lastUpdatedRaw);
          if (!lastUpdated || !Number.isFinite(ttlHours) || ttlHours <= 0) {
            return false;
          }
          const ttlMs = ttlHours * 60 * 60 * 1000;
          if (Date.now() - lastUpdated > ttlMs) {
            clearAllAppStorage();
            return true;
          }
          return false;
        };

        migrateLegacyStorage();
        const INITIAL_APP_DATA = loadAppData();
        const storedTtlOverride = INITIAL_APP_DATA.settings.ttlHoursOverride ?? getKey('ttlHoursOverride', null);
        const initialTtlHours = Number.isFinite(storedTtlOverride) && storedTtlOverride > 0
          ? storedTtlOverride
          : DEFAULT_TTL_HOURS;
        const INITIAL_STORAGE_EXPIRED = applyStorageExpiration(initialTtlHours);

        const MANAGEMENT_SUBTABS = ['ich', 'ischemic', 'sah', 'tia', 'cvt', 'calculators'];

        const RESEARCH_SUBTABS = ['guidelines', 'references'];

        const LEGACY_MANAGEMENT_TABS = {
          ich: 'ich',
          protocols: 'ischemic',
          calculators: 'calculators',
          references: 'references',
          evidence: 'references',
          teaching: 'references',
          // Removed sub-tabs — redirect persisted user state to a sensible neighbor.
          clinic: 'ischemic',
          wards: 'ischemic',
          'pocket-cards': 'ischemic'
        };

        const normalizeManagementSubTab = (value) => {
          if (!value) return null;
          const normalized = String(value).toLowerCase();
          if (MANAGEMENT_SUBTABS.includes(normalized)) return normalized;
          if (LEGACY_MANAGEMENT_TABS[normalized]) return LEGACY_MANAGEMENT_TABS[normalized];
          return null;
        };

        const normalizeResearchSubTab = (value) => {
          if (!value) return null;
          const normalized = String(value).toLowerCase();
          if (RESEARCH_SUBTABS.includes(normalized)) return normalized;
          if (normalized === 'whats-new' || normalized === "what's-new" || normalized === 'whatsnew') return 'whatsnew';
          return null;
        };

        const VALID_TABS = [
          'encounter',
          'protocols',
          'research',
          'trials',
          'management',
          'library',
          'education',
          'settings'
        ];

        const parseHashRoute = (hash) => {
          if (!hash) return { tab: 'encounter' };
          const cleaned = hash.replace(/^#\/?/, '').trim();
          if (!cleaned) {
            return { tab: 'encounter' };
          }
          const parts = cleaned.split('/').filter(Boolean);
          const root = parts[0];
          const sub = parts[1];

          switch (root) {
            case 'dashboard':
            case 'home':
              return { tab: 'encounter' };
            case 'encounter':
              return { tab: 'encounter' };
            case 'protocols':
              if (sub === 'simulators') {
                return { tab: 'education', sub: 'simulators' };
              }
              if (sub === 'references') {
                return { tab: 'research', sub: 'references' };
              }
              return { tab: 'protocols', sub: normalizeManagementSubTab(sub) };
            case 'library':
            case 'management':
              if (sub === 'simulators') {
                return { tab: 'education', sub: 'simulators' };
              }
              if (sub === 'references') {
                return { tab: 'research', sub: 'references' };
              }
              return { tab: 'protocols', sub: normalizeManagementSubTab(sub) };
            case 'settings':
              return { tab: 'settings' };
            case 'ich':
            case 'calculators':
              return { tab: 'protocols', sub: LEGACY_MANAGEMENT_TABS[root] };
            case 'evidence':
            case 'teaching':
            case 'references':
              return { tab: 'research', sub: 'references' };
            case 'research':
              return { tab: 'research', sub: normalizeResearchSubTab(sub) };
            case 'trials':
              return { tab: 'trials' };
            case 'education':
              return { tab: 'education', sub };
            default:
              return null;
          }
        };

        const buildHashRoute = (tab, sub) => {
          switch (tab) {
            case 'home':
              return '#/encounter';
            case 'encounter':
              return '#/encounter';
            case 'settings':
              return '#/settings';
            case 'protocols':
            case 'library':
            case 'management': {
              const managementSub = normalizeManagementSubTab(sub);
              return managementSub ? `#/protocols/${managementSub}` : '#/protocols';
            }
            case 'research':
              return sub ? `#/research/${sub}` : '#/research';
            case 'trials':
              return '#/trials';
            case 'education':
              return sub ? `#/education/${sub}` : '#/education';
            default:
              return '#/encounter';
          }
        };


const AutoDetectedContraindicationsBanner = ({ autoAbsolute, autoRelative, autoCautionary }) => {
  if (autoAbsolute.length > 0) {
    return (
      <div className="bg-crit-100 border-2 border-crit-400 rounded-lg p-3 dark:bg-crit-950">
        <div className="flex items-center gap-2 mb-1">
          <span className="bg-crit-600 text-white px-2 py-0.5 rounded text-xs font-bold">AUTO-DETECTED</span>
          <span className="text-sm font-bold text-crit-900 dark:text-crit-300">TNK Contraindication{autoAbsolute.length > 1 ? 's' : ''} Found From Patient Data</span>
        </div>
        <ul className="text-xs text-crit-800 space-y-0.5 ml-2 dark:text-crit-300">
          {autoAbsolute.map(c => <li key={c.id}>&#10007; <strong>{c.label}</strong>{c.note ? ` (${c.note})` : ''}</li>)}
        </ul>
      </div>
    );
  }

  if (autoRelative.length > 0) {
    return (
      <div className="bg-warn-100 border-2 border-warn-400 rounded-lg p-3 dark:bg-warn-900">
        <div className="flex items-center gap-2 mb-1">
          <span className="bg-warn-500 text-white px-2 py-0.5 rounded text-xs font-bold">AUTO-DETECTED</span>
          <span className="text-sm font-bold text-warn-900 dark:text-warn-300">{autoRelative.length} Relative Contraindication{autoRelative.length > 1 ? 's' : ''} — Use Clinical Judgment</span>
        </div>
        <ul className="text-xs text-warn-800 space-y-0.5 ml-2 dark:text-warn-300">
          {autoRelative.map(c => <li key={c.id}>&#9888; {c.label}{c.note ? ` (${c.note})` : ''}</li>)}
        </ul>
      </div>
    );
  }

  if (autoCautionary.length > 0) {
    return (
      <div className="bg-cobalt-50 border-2 border-cobalt-300 rounded-lg p-3 dark:bg-cobalt-900 dark:border-cobalt-700">
        <div className="flex items-center gap-2 mb-1">
          <span className="bg-cobalt-500 text-white px-2 py-0.5 rounded text-xs font-bold dark:bg-cobalt-700">AUTO-DETECTED</span>
          <span className="text-sm font-bold text-cobalt-900 dark:text-cobalt-300">{autoCautionary.length} Cautionary Condition{autoCautionary.length > 1 ? 's' : ''} — IVT Benefit Outweighs Risk</span>
        </div>
        <ul className="text-xs text-cobalt-800 space-y-0.5 ml-2 dark:text-cobalt-300">
          {autoCautionary.map(c => <li key={c.id}>&#8505; {c.label}{c.note ? ` (${c.note})` : ''}</li>)}
        </ul>
      </div>
    );
  }

  return null;
};

